use super::{error::{KnowledgeError,KnowledgeErrorCode},model::IntegrityIssue}; use rusqlite::Connection;
pub fn run(c:&Connection)->Result<Vec<IntegrityIssue>,KnowledgeError>{let checks=[("dangling","SELECT assertion_id FROM assertions a WHERE NOT EXISTS(SELECT 1 FROM entities e WHERE e.entity_id=a.subject_entity_id) OR NOT EXISTS(SELECT 1 FROM entities e WHERE e.entity_id=a.object_entity_id)"),("evidence_less_ingest","SELECT assertion_id FROM assertions a WHERE origin='ingest' AND NOT EXISTS(SELECT 1 FROM assertion_evidence e WHERE e.assertion_id=a.assertion_id)"),("unused_entity","SELECT entity_id FROM entities e WHERE NOT EXISTS(SELECT 1 FROM graph_nodes n WHERE n.entity_id=e.entity_id) AND NOT EXISTS(SELECT 1 FROM page_entities p WHERE p.entity_id=e.entity_id) AND NOT EXISTS(SELECT 1 FROM assertions a WHERE a.subject_entity_id=e.entity_id OR a.object_entity_id=e.entity_id)"),("unused_tag","SELECT tag_id FROM tags t WHERE NOT EXISTS(SELECT 1 FROM page_tags p WHERE p.tag_id=t.tag_id)")];let mut out=vec![];for(category,q)in checks{let mut s=c.prepare(q).map_err(|e|KnowledgeError::new(KnowledgeErrorCode::ValidationFailed,e.to_string()))?;let rows=s.query_map([],|r|r.get::<_,String>(0)).map_err(|e|KnowledgeError::new(KnowledgeErrorCode::ValidationFailed,e.to_string()))?;for row in rows{out.push(IntegrityIssue{category:category.into(),message:format!("{category} record"),record_id:Some(row.map_err(|e|KnowledgeError::new(KnowledgeErrorCode::ValidationFailed,e.to_string()))?)})}}Ok(out)}
